import { useEffect, useState } from 'react';
import { loadStripe, type Stripe } from '@stripe/stripe-js';
import { Elements, PaymentElement, useStripe, useElements } from '@stripe/react-stripe-js';
import { meApi, type Plan } from '../lib/api';

declare global {
  interface Window { STRIPE_PUBLISHABLE_KEY?: string; }
}

const CURRENCY_LOCALE: Record<string, string> = { usd: 'en-US', cad: 'en-CA', aud: 'en-AU' };

function fmtPrice(cents: number, currency: string): string {
  return (cents / 100).toLocaleString(CURRENCY_LOCALE[currency] ?? 'en-US', {
    style: 'currency',
    currency: currency.toUpperCase(),
    maximumFractionDigits: 0,
  });
}

let _stripePromise: Promise<Stripe | null> | null = null;
let _cachedKey: string | undefined;
function getStripePromise(): Promise<Stripe | null> {
  const key = window.STRIPE_PUBLISHABLE_KEY ?? '';
  if (!_stripePromise || _cachedKey !== key) {
    _cachedKey = key;
    _stripePromise = loadStripe(key);
  }
  return _stripePromise;
}

function trialEndLabel(): string {
  const d = new Date();
  d.setDate(d.getDate() + 90);
  return d.toLocaleDateString(undefined, { month: 'long', day: 'numeric', year: 'numeric' });
}

function PayForm({ plan, onDone }: { plan: Plan; onDone: () => void }): JSX.Element {
  const stripe = useStripe();
  const elements = useElements();
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState<string | null>(null);

  const submit = async (e: React.FormEvent): Promise<void> => {
    e.preventDefault();
    if (!stripe || !elements) return;
    setBusy(true);
    setErr(null);
    const { error, setupIntent } = await stripe.confirmSetup({
      elements,
      confirmParams: { return_url: window.location.href },
      redirect: 'if_required',
    });
    if (error) { setErr(error.message ?? 'Payment failed'); setBusy(false); return; }
    const pmId =
      typeof setupIntent?.payment_method === 'string'
        ? setupIntent.payment_method
        : setupIntent?.payment_method?.id;
    if (!pmId) { setErr('No payment method returned by Stripe'); setBusy(false); return; }
    try {
      await meApi.subscribe(plan.id, pmId);
      onDone();
    } catch (e2) {
      setErr(String(e2));
    } finally {
      setBusy(false);
    }
  };

  return (
    <form onSubmit={submit} className="space-y-4">
      {plan.priceCents > 0 && (
        <div className="rounded-lg border border-primary/20 bg-primary/10 px-4 py-3 text-sm text-foreground">
          <span className="font-semibold">90-day free trial</span> — no charge until{' '}
          <strong>{trialEndLabel()}</strong>, then{' '}
          {fmtPrice(plan.priceCents, plan.currency)}/
          {plan.interval === 'year' ? 'yr' : 'mo'}.
        </div>
      )}
      <PaymentElement />
      {err && (
        <div className="rounded border border-destructive/20 bg-destructive/10 p-2 text-sm text-destructive">
          {err}
        </div>
      )}
      <button
        type="submit"
        disabled={!stripe || busy}
        className="w-full rounded-lg bg-primary px-4 py-2.5 text-sm font-medium text-primary-foreground hover:bg-primary/90 disabled:opacity-50"
      >
        {busy ? 'Processing…' : `Start trial — ${plan.name}`}
      </button>
    </form>
  );
}

export function SubscribeModal({
  plan, onClose, onDone,
}: {
  plan: Plan; onClose: () => void; onDone: () => void;
}): JSX.Element {
  const [clientSecret, setClientSecret] = useState<string | null>(null);
  const [step, setStep] = useState<1 | 2>(1);
  const [err, setErr] = useState<string | null>(null);

  useEffect(() => {
    meApi.intent()
      .then((r) => { setClientSecret(r.clientSecret); setStep(2); })
      .catch((e: unknown) => setErr(String(e)));
  }, []);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60">
      <div className="w-[480px] rounded-xl border border-border bg-card p-6 shadow-2xl">
        <div className="mb-4 flex items-center justify-between">
          <h3 className="text-lg font-semibold text-foreground">Subscribe to {plan.name}</h3>
          <button
            onClick={onClose}
            aria-label="close"
            className="text-xl text-muted-foreground hover:text-foreground"
          >
            ×
          </button>
        </div>

        {/* Step indicator */}
        <div className="mb-5 flex items-center gap-2 text-xs">
          <span className={`font-medium ${step >= 1 ? 'text-primary' : 'text-muted-foreground'}`}>
            1. Plan selected
          </span>
          <span className="text-muted-foreground">→</span>
          <span className={`font-medium ${step >= 2 ? 'text-primary' : 'text-muted-foreground'}`}>
            2. Payment details
          </span>
        </div>

        {err && (
          <div className="rounded border border-destructive/20 bg-destructive/10 p-3 text-sm text-destructive">
            {err}
          </div>
        )}

        {!clientSecret && !err && (
          <div className="py-6 text-center text-sm text-muted-foreground">Preparing checkout…</div>
        )}

        {clientSecret && (
          <Elements
            stripe={getStripePromise()}
            options={{ clientSecret, appearance: { theme: 'night' } }}
          >
            <PayForm plan={plan} onDone={onDone} />
          </Elements>
        )}
      </div>
    </div>
  );
}
